#!/usr/bin/env python3
"""
mkt-christ commentary -- Hosea chapters 1-6 (84 verses)
Run: python3 scripts/zc-christ-hosea-1-6-full.py

Christological classifications used:
  direct   -- explicit NT citation or quotation
  allusion -- NT verbal or conceptual echo
  type     -- OT figure/event fulfilled in Christ/church
  shadow   -- institution/pattern prefiguring Christ
  theme    -- theological principle fully expressed in Christ

Key NT connections:
  1:10 -> Rom 9:26; 1 Pet 2:10 (sons of the living God -- direct)
  2:23 -> Rom 9:25; 1 Pet 2:10 (Lo-ammi/Lo-ruhamah reversed -- direct)
  3:1  -> Eph 5:25 (love the adulteress -- type)
  3:2  -> 1 Pet 1:18-19 (redemption price -- type)
  3:5  -> Luke 1:32-33; John 7:42 (David their king -- direct)
  4:6  -> John 1:14; Col 2:3 (knowledge of God in Christ -- theme)
  5:15 -> Acts 1:9-11; Heb 9:28 (return to place / second coming -- allusion)
  6:2  -> 1 Cor 15:4 (third day raised -- allusion)
  6:6  -> Matt 9:13; 12:7 (I desire mercy not sacrifice -- direct)
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HOSEA = {
    "1": {
        "1": "<p>The superscription grounds Hosea's message in the prophetic Word (<em>devar-YHWH</em>). John's prologue identifies Christ as the <em>Logos</em> -- the Word of God in person (John 1:1, 14). What Hosea received as a word coming to him is, in Christ, the Word who has come as a human being. Every prophetic 'the word of the LORD came to me' anticipates the incarnation, in which the divine Word does not merely arrive in human speech but takes up human flesh. Christ is the fullness of what every prophetic word partial disclosed.</p>",
        "2": "<p class='christ-type'>YHWH commands Hosea to take 'a wife of unfaithfulness' as an enacted parable of YHWH's own covenant situation with Israel. The Hosea-Gomer marriage is the primary OT type of the Christ-Church relationship. Paul's command in Eph 5:25 -- 'Husbands, love your wives, as Christ loved the church and gave himself up for her' -- applies the very same marriage metaphor: the unfaithful wife is loved and pursued by the faithful husband at personal cost. Christ is the ultimate Hosea -- the faithful covenant partner who pursues and redeems the unfaithful bride not with words but with his own life given as the redemption price.</p>",
        "3": "<p class='christ-type'>Gomer's name carries the root meaning 'completion/coming to an end' -- she who embodies the completion of Israel's unfaithfulness. As Hosea married Gomer in covenantal obedience, Christ united himself to humanity -- a humanity equally compromised by covenant unfaithfulness. The incarnation is the ultimate act of the faithful groom who does not await the bride's reformation before committing himself: 'while we were still sinners, Christ died for us' (Rom 5:8). The marriage that begins in Hosea's obedience anticipates the marriage covenant that begins in Christ's incarnation.</p>",
        "4": "<p class='christ-type'>The name Jezreel ('God sows') becomes the name of both judgment and restoration. In Christ, the judgment principle of Jezreel is absorbed: 'he was wounded for our transgressions' (Isa 53:5); the house of Jehu's blood-guilt points toward the ultimate reckoning that Christ endures on behalf of all blood-guilt. The restoration dimension -- 'God sows' -- finds its fullness in Christ as the seed planted in the earth (John 12:24: 'unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit'). The sowing of Christ in death produces the harvest of the resurrection community.</p>",
        "5": "<p class='christ-theme'>The breaking of the bow of Israel in the valley of Jezreel is the covenant judgment made concrete. But the same bow reappears in 2:18 as the instrument of peace -- 'I will abolish the bow, the sword, and warfare from the land.' Christ is the one through whom both movements are fulfilled: he absorbs the judgment of the broken covenant ('becoming a curse for us,' Gal 3:13) and establishes the peace by which the bow of warfare is finally broken. Rev 6:2 shows a rider with a bow going out to conquer -- but Christ's conquest is achieved not by military bow but by the cross. The bow of judgment becomes the arc of covenant peace.</p>",
        "6": "<p class='christ-type'>Lo-ruhamah ('Not Pitied/Not Loved') is the name that negates the divine compassion -- the deepest attribute of the covenant God (Exod 34:6-7: 'merciful and gracious, slow to anger, abounding in steadfast love'). In Christ, the Lo-ruhamah condition is reversed definitively: 'God so loved the world' (John 3:16); 'the Father himself loves you' (John 16:27). The name's reversal in 2:23 and its NT citation in Rom 9:25 and 1 Pet 2:10 identify the church as the Lo-ruhamah who has become Ruhamah -- those who had no claim on divine compassion now called 'beloved.' The cross is the event at which Lo-ruhamah becomes Ruhamah: Christ absorbs the 'not pitied' so that his people receive the pity.</p>",
        "7": "<p class='christ-theme'>Judah's salvation 'by the LORD their God' -- not by bow or sword or warfare, horses or horsemen -- announces the paradox of divine deliverance: salvation through means that appear humanly insufficient. This theme reaches its climax in the cross: the death of Christ appears to be the opposite of deliverance, yet it is the supreme act of salvation (1 Cor 1:18-25). 'The weakness of God is stronger than human strength.' The Hezekiah deliverance from Sennacherib (2 Kgs 19:35) -- perhaps the immediate fulfillment -- is a shadow of the cross, where YHWH defeats the ultimate enemy not by military force but by absorbing its power in his own death and resurrection.</p>",
        "8": "<p class='christ-type'>After Gomer weans Lo-ruhamah, she conceives again -- the birth of the third child follows the pattern of increasing estrangement and hardening of the covenant dissolution. In the typology, each successive child represents Israel's deepening alienation from YHWH under successive generations of idolatry. Christ enters this history of accumulating failure at its most desperate point -- not when Israel was near the covenant ideal but at the nadir of exile and dispersal. He comes not to those who have maintained covenant fidelity but to the lost, the alienated, the ones who have multiplied transgressions across the generations.</p>",
        "9": "<p class='christ-type'>Lo-ammi -- 'Not My People' -- is the formal negation of the covenant formula. The negation of <em>ehyeh</em> ('I am not') reverses the divine name declared at the burning bush (Exod 3:14: 'I AM'). In Christ, the Lo-ammi condition is reversed at its root: 'He came to his own, and his own people did not receive him. But to all who did receive him... he gave the right to become children of God' (John 1:11-12). The covenant formula dissolved in Lo-ammi ('you are not my people / I am not your God') is reconstituted in Christ: 'I will be their God, and they shall be my people' (2 Cor 6:16; Heb 8:10; Rev 21:3). The 'I AM' who seemed absent returns in the person of Jesus ('I AM the way, the truth, and the life,' John 14:6).</p>",
        "10": "<p class='christ-direct'>The promise that in the very place of Lo-ammi declaration, Israel's children will be called 'sons of the living God' (<em>El Chai</em>) is explicitly cited in the NT for the inclusion of Gentiles in Christ. Paul quotes it in Rom 9:26 to demonstrate that the covenant restoration language applies to all who were once 'not my people' -- including Gentiles. Peter applies it in 1 Pet 2:9-10 to the church: 'Once you were not a people, but now you are God's people; once you had not received mercy, but now you have received mercy.' Christ is the reason the Lo-ammi become sons of El Chai: through union with the Son of the living God, those who had no filial standing receive adoption (Rom 8:15; Gal 4:5).</p>",
        "11": "<p class='christ-type'>The eschatological reunion of Israel and Judah under 'one head' points directly to the messianic king who unites the divided kingdom. Christ is the 'one head' over all his people: 'he is the head of the body, the church' (Col 1:18); 'one Lord, one faith, one baptism' (Eph 4:5). The going-up from the land (<em>ve-alu min-ha-aretz</em>) echoes the Exodus and anticipates the final ingathering. Rev 7:4-9 pictures the redeemed from every tribe gathered under the one Lamb -- the fulfillment of the one-head vision that Hosea projects into the eschatological future. 'Great is the day of Jezreel' -- God's ultimate sowing produces the great harvest under the one shepherd-king.</p>"
    },
    "2": {
        "1": "<p class='christ-direct'>The command to call the brothers 'My people' and the sisters 'My beloved' is the enacted reversal of chs 1:6, 9. In the NT, this reversal is accomplished in Christ: those who were Lo-ammi become Ammi; those who were Lo-ruhamah become Ruhamah. Peter's application (1 Pet 2:10) and Paul's application (Rom 9:25) identify the church as the community in which this reversal has taken place. Christ is the one through whom the reversal occurs -- in him the covenant formula is reconstituted ('I will be your God and you will be my people,' 2 Cor 6:16). The command to speak these new names to one another is fulfilled when the church confesses 'you are my people' over every new believer who enters the covenant community through baptism.</p>",
        "2": "<p class='christ-theme'>The covenant lawsuit (<em>riv</em>) YHWH brings against unfaithful Israel is the OT's formal mechanism for addressing covenant breach. Christ enters this lawsuit not as the plaintiff's attorney but as the one who absorbs the judgment the lawsuit would produce. In legal terms, he is the <em>go'el</em> (kinsman-redeemer) who takes the verdict upon himself. Paul's forensic theology in Romans is the NT form of the <em>riv</em>: 'There is therefore now no condemnation for those who are in Christ Jesus' (Rom 8:1) -- the lawsuit's outcome is diverted from the guilty party to the one who bore the penalty in their place. The divorce declared in 2:2 is reversed by Christ's self-giving love (Eph 5:25).</p>",
        "3": "<p class='christ-theme'>The threat of stripping naked and exposing as on the day of birth (the covenant curse of total vulnerability and shame) is the punishment that the unfaithful wife deserves. Christ endures this covenant curse in his passion: stripped of garments (John 19:23-24), exposed and shamed before accusers (Mark 15:27-32), hung naked in the open. He who had no unfaithfulness receives the punishment for those who do. The 'nakedness' of the covenant curse falls on him so that his people can be clothed in his righteousness (Rev 3:18; 19:8).</p>",
        "4": "<p class='christ-theme'>The children who share in the mother's judgment represent the corporate solidarity of sin's consequences. Christ reverses this solidarity: he does not merely excuse the children of unfaithfulness but, by being united to them, bears their inherited condition. 'As in Adam all die, so also in Christ shall all be made alive' (1 Cor 15:22). The corporate guilt transmitted through Adam (the first husband who also failed) is met by the corporate righteousness transmitted through Christ (the new Adam who does not fail). The Lo-ruhamah children become Ruhamah not by their own reformation but by adoption into the faithful Son.</p>",
        "5": "<p class='christ-theme'>Israel's attribution of covenant gifts to the Baals rather than to YHWH is the diagnostic error that Christ addresses at the root. He came as the true provider of all that the creation offers: 'Every good gift and every perfect gift is from above, coming down from the Father of lights' (Jas 1:17). The incarnation is YHWH becoming visible as the source of all provision -- so that the attribution error that drove Israel to idolatry is resolved by the unmistakable personal presence of the Giver. 'I am the bread of life' (John 6:35) names Christ as the provider of what Israel attributed to grain and wine and oil, and to the Baals who supposedly bestowed them.</p>",
        "6": "<p class='christ-theme'>YHWH blocks the paths of the unfaithful wife with thorns so she cannot reach her false lovers. The thorn imagery recurs in the NT at the crucifixion: the crown of thorns placed on Christ's head (Matt 27:29; John 19:2) -- the curse-symbol of Gen 3:18 ('thorns and thistles') applied to the one who bears the covenant curse. Christ wears the thorns of the curse so that the paths of his people are cleared: 'I am the way' (John 14:6). The hedge of thorns that was punishment for the unfaithful bride becomes the thorny crown borne by the faithful bridegroom who clears the way for her return.</p>",
        "7": "<p class='christ-theme'>Israel's return to 'my first husband' because it was better before is the OT's image of prodigal repentance -- returning not from love but from hunger. Christ's parable of the prodigal son (Luke 15:17-20) mirrors this exactly: 'he came to himself' and said 'I will arise and go to my father.' The motive is mixed -- suffering has clarified what was better. But the father runs to meet the returning son: Christ does not wait for his people to return in perfect love before welcoming them. The prodigal return is met by the extravagant welcome of the bridegroom who has been waiting.</p>",
        "8": "<p class='christ-theme'>Israel's failure to know (<em>lo yadah</em>) that YHWH was the source of all the covenant gifts is the ignorance that the incarnation addresses directly. Christ came as the visible, tangible revelation of the one who provides all things: 'the Word became flesh' (John 1:14) so that YHWH's provision could no longer be misattributed. John's Gospel is structured around seven 'I AM' declarations of Christ that identify him as the true source of what the Baals falsely claimed to provide: bread of life (John 6:35), light (8:12), gate (10:9), shepherd (10:11), resurrection (11:25), way/truth/life (14:6), vine (15:5).</p>",
        "9": "<p class='christ-theme'>YHWH reclaims 'my grain, my wine, my oil' -- the possessive pronoun marks the gifts as his even when given to Israel. Christ's eucharistic words at the Last Supper enact this possessive reclamation: 'This is my body... this is my blood' (Matt 26:26-28). The grain and wine of the covenant meal are identified as Christ himself -- the ultimate form of YHWH's possessive claim on the gifts he gives. The bread and cup are not merely symbols but the means by which Christ personally gives himself as the covenant provision that no idolatry can counterfeit.</p>",
        "10": "<p class='christ-theme'>The exposure of Israel's shameful nakedness before the lovers who fail to protect her mirrors the humiliation that the gospel addresses. Christ's death exposed the ultimate nakedness of human helplessness before sin and death -- and his resurrection revealed that only YHWH-in-Christ can rescue from the hand of the ultimate enemy. 'No one can rescue from my hand' (2:10) is the divine exclusivity that the incarnation makes personal: only the God who took flesh could do what no false lover can do, rescuing his people from the power of sin and death (Rom 8:31-34).</p>",
        "11": "<p class='christ-shadow'>The cessation of Israel's covenant festivals -- chag, chodesh, Shabbat -- is the shadow-side of the fulfillment Christ brings. Christ is the substance of which all the appointed times were shadows: 'These are a shadow of the things to come, but the substance belongs to Christ' (Col 2:17). The Sabbath finds its fulfillment in Christ's rest (Matt 11:28-29: 'Come to me... and I will give you rest'); the festivals find their fulfillment in his death (Passover) and the Spirit's outpouring (Pentecost/Shavuot). The suspension of the shadow-calendar in Hosea's judgment anticipates the new calendar centered on Christ himself.</p>",
        "12": "<p class='christ-theme'>The ruin of the vines and fig trees that Israel attributed to the Baals is reversed in Christ's parable of the vine: 'I am the true vine, and my Father is the vinedresser' (John 15:1). The vines that were ruined when falsely attributed to the Baals flourish when the true Vinedresser is known. Christ does not merely restore what was lost; he replaces the false attribution with the true: the vine is not the product of Baal-fertility but of the Father's care and the Son's self-giving. 'Apart from me you can do nothing' (John 15:5) -- the fruitfulness that idolatry promised and could not deliver is freely given through union with Christ.</p>",
        "13": "<p class='christ-theme'>Israel forgot YHWH while adorning herself for the Baals. The forgetting of YHWH is addressed in Christ through the Spirit's ministry: 'the Helper, the Holy Spirit, whom the Father will send in my name, he will teach you all things and bring to your remembrance all that I have said to you' (John 14:26). The Spirit given at Pentecost is the antidote to the forgetting that Hosea diagnoses: he makes remembrance of Christ the ongoing reality of the new covenant community. The Eucharist is also the institution of remembrance: 'Do this in remembrance of me' (Luke 22:19) -- the covenant meal that keeps YHWH-in-Christ from being forgotten.</p>",
        "14": "<p class='christ-allusion'>YHWH's strategy of alluring Israel into the wilderness to speak tenderly to her is the OT anticipation of the incarnation's form: God coming near, speaking personally, wooing the estranged beloved. The wilderness of the new exodus is the ministry of John the Baptist ('A voice crying in the wilderness,' Matt 3:3) and Jesus's own forty-day wilderness testing -- in which the second Adam overcomes what the first Adam failed at, and what Israel in the wilderness repeated. Christ's tender words -- 'Come to me, all who labor and are heavy laden' (Matt 11:28) -- are the <em>dibarti al-libah</em> ('I will speak to her heart') of the new covenant.</p>",
        "15": "<p class='christ-allusion'>The Valley of Achor (trouble/distress) becoming a door of hope is fulfilled in the cross: the place of ultimate trouble -- death, judgment, God-forsakenness (Mark 15:34) -- becomes the threshold of hope for all who trust in Christ. 'He who did not spare his own Son but gave him up for us all' (Rom 8:32) makes the place of the greatest suffering the place of the greatest hope. Hosea's valley of trouble-turned-hope is the OT's compressed image of Good Friday/Easter: the very site of the curse is the doorway to life. Israel's response 'as in the days of her youth' points to the new creation freshness of resurrection life.</p>",
        "16": "<p class='christ-type'>The covenant's renewal on the terms of <em>ishi</em> (intimate husband) rather than <em>baali</em> (lord/master) points to the relational quality of the new covenant in Christ. In the old covenant, the law-structure was primary -- covenant as legal obligation (<em>baali</em>, the authority-title). In the new covenant, the relationship is primary -- the Spirit of adoption by whom we cry 'Abba, Father' (Rom 8:15). Christ does not relate to his church as a master to servants but as a husband to a wife (Eph 5:25-32): 'No longer do I call you servants... but I have called you friends' (John 15:15). The <em>ishi</em>-relationship is the NT norm -- intimate, freely chosen, mutually self-giving.</p>",
        "17": "<p class='christ-theme'>The removal of the Baal-names from Israel's lips is accomplished in Christ through the proclamation of his name as the only name of salvation: 'there is no other name under heaven given among men by which we must be saved' (Acts 4:12). The monotheistic exclusivity of the new covenant -- 'one Lord, one faith, one baptism, one God and Father of all' (Eph 4:5-6) -- fulfills Hosea's promise that the Baal-names will be purged. The NT's insistence that Jesus is the only mediator (1 Tim 2:5) is not triumphalism but the fulfillment of YHWH's promise: when the one true name is known, there are no other names to be mentioned.</p>",
        "18": "<p class='christ-shadow'>The eschatological covenant with wild animals, birds, and creeping things -- abolishing bow, sword, and warfare from the land -- is the OT vision of new creation shalom. Christ's resurrection initiates this new creation: 'If anyone is in Christ, he is a new creation' (2 Cor 5:17). The reconciliation of all creation that Hosea envisions (and that Paul describes in Rom 8:19-22: creation waiting for the sons of God to be revealed) is secured by Christ's cross -- through him God reconciles 'all things, whether on earth or in heaven, making peace by the blood of his cross' (Col 1:20). The final abolition of warfare awaits the new creation (Rev 21:4: 'no more... death, mourning, crying, or pain').</p>",
        "19": "<p class='christ-type'>The triple betrothal formula -- 'I will betroth you to me forever; I will betroth you in righteousness and justice, in covenant loyalty and compassion' -- is the OT's most concentrated vision of the covenant relationship restored to its permanent, character-grounded form. Paul uses the same betrothal language for the Christ-church relationship: 'I betrothed you to one husband, to present you as a pure virgin to Christ' (2 Cor 11:2). The four attributes of the betrothal (righteousness, justice, chesed, compassion) are the character of Christ -- the one in whom all four are fully expressed and through whose righteousness they become the standing of his bride (2 Cor 5:21).</p>",
        "20": "<p class='christ-type'>The fifth attribute of the betrothal -- faithfulness (<em>emunah</em>) -- and the promised outcome 'you will know the LORD' are fulfilled in Christ. He is the faithful one (<em>ho pistos</em>, Rev 19:11) through whose faithfulness his people receive covenant standing. The promised knowledge of YHWH is realized in Christ: 'I have made known to them your name' (John 17:26); 'This is eternal life, that they know you, the only true God, and Jesus Christ whom you have sent' (John 17:3). The intimate knowledge that Hosea calls the center of covenant life is given in Christ's person -- to know Christ is to know the Father (John 14:9).</p>",
        "21": "<p class='christ-theme'>The chain of responses -- YHWH to heaven, heaven to earth, earth to grain, wine, oil -- describes the cascade of covenant renewal flowing through the creation order. Christ is the initiator of this chain in the new creation: the Father raises the Son; the Son sends the Spirit; the Spirit transforms the community; the community transforms the creation's story. Paul's cosmic reconciliation (Col 1:20) and creation-liberation (Rom 8:21) describe the same cascade: YHWH's act in Christ flows through history and creation until the whole order is renewed. 'Behold, I am making all things new' (Rev 21:5).</p>",
        "22": "<p class='christ-theme'>The earth responding to the grain, wine, and oil -- and they to Jezreel -- completes the chain of covenant renewal. The Eucharist is the new covenant enactment of this chain: Christ gives himself as the bread and the cup; those who receive him become the community that bears his life into the world; through their witness, the creation's story is being written toward its renewal. The grain and wine of 2:22 find their ultimate form in the Eucharistic elements that mediate Christ's body and blood -- the covenant gifts reclaimed from Baal-attribution and given their true identity as gifts of the Son.</p>",
        "23": "<p class='christ-direct'>The climactic triple reversal -- 'I will plant her... I will show mercy to Lo-ruhamah... I will say to Lo-ammi, You are my people' -- is quoted in the NT as fulfilled in the inclusion of Gentiles through Christ. Paul cites it in Rom 9:25: 'As indeed he says in Hosea, Those who were not my people I will call my people, and her who was not beloved I will call beloved.' Peter applies it to the church in 1 Pet 2:10: 'Once you were not a people, but now you are God's people.' The fulfillment: in Christ, through the Spirit, those who had no covenant standing are given the fullness of covenant belonging. The Lo-ammi who cry 'My God' (v.23b) are all who confess 'Jesus is Lord' -- the new covenant form of the bilateral covenant formula.</p>"
    },
    "3": {
        "1": "<p class='christ-type'>The divine command to love again a woman who is loved by another and is an adulteress -- 'just as YHWH loves the children of Israel' -- is the OT's most direct statement of the love that persists through unfaithfulness. In Christ this love becomes the explicit standard: 'God shows his love for us in that while we were still sinners, Christ died for us' (Rom 5:8). The adulterous woman of ch 3 is the type of all who come to Christ having given their loyalty to other masters: 'You also have died to the law through the body of Christ, so that you may belong to another, to him who has been raised from the dead' (Rom 7:4). The love that Hosea is commanded to sustain is the love that Christ demonstrates on the cross.</p>",
        "2": "<p class='christ-type'>Hosea's purchase of the unfaithful woman for fifteen pieces of silver and barley is a type of the redemption Christ accomplishes. The redemption price points to Christ's blood as the ransom: 'You were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold, but with the precious blood of Christ, like that of a lamb without blemish or spot' (1 Pet 1:18-19). Hosea pays a price for Gomer in her degraded state; Christ pays the ultimate price for those degraded by sin. The arithmetic of redemption (fifteen pieces of silver, less than a slave's price) signals the humiliated condition of the one redeemed -- Christ dies for those who have forfeited every claim on value.</p>",
        "3": "<p class='christ-shadow'>The terms Hosea sets -- stay with me, no prostitution, no other man, and even Hosea himself will wait -- describe a period of waiting and purification before full marital restoration. This is a shadow of the inter-advent period: Christ has redeemed his church (cross), claimed her, but the full consummation of the marriage awaits his return (Rev 19:7-9: 'the marriage of the Lamb has come, and his Bride has made herself ready'). The church is betrothed but the wedding feast is future; the waiting period demands faithfulness (no prostitution to other lords) while the bridegroom is away (cf. Matt 25:1-13, the virgins waiting for the bridegroom).</p>",
        "4": "<p class='christ-shadow'>The many days without king, ruler, sacrifice, pillar, ephod, or teraphim describe the suspension of Israel's political and cultic institutions during exile. This suspension is a shadow of the new covenant's transformation: in Christ, the need for all these institutions is fulfilled and transcended. There is no temple because God and the Lamb are its temple (Rev 21:22); no king but the King of kings; no sacrifice because the once-for-all offering has been made (Heb 9:26-28); no ephod because the Spirit gives direct access to divine guidance. The suspension of the old institutions prepares for the installation of the new -- Christ as the fulfillment of each.</p>",
        "5": "<p class='christ-direct'>The promise that Israel will 'seek the LORD their God and David their king' in the latter days identifies the messianic king as the one who reunites the repentant people. The NT identifies Jesus as this Davidic king: 'He will be great and will be called the Son of the Most High. And the Lord God will give to him the throne of his father David' (Luke 1:32); 'Is not this the Christ, the descendant of David, who comes from Bethlehem?' (John 7:42). The trembling approach to YHWH and his goodness in the latter days is fulfilled for all who come to Christ in repentance: 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28). Christ is the David their king for whom Hosea's Israel waits.</p>"
    },
    "4": {
        "1": "<p class='christ-theme'>The absence of <em>emet</em> (faithfulness), <em>chesed</em> (covenant love), and <em>daath Elohim</em> (knowledge of God) from the land is the diagnosis that Christ's coming addresses comprehensively. He is himself the fullness of all three: <em>emet</em> -- 'I am... the truth' (John 14:6) and 'grace and truth came through Jesus Christ' (John 1:17); <em>chesed</em> -- 'God so loved the world' (John 3:16) and the greatest expression of covenant love in the cross; <em>daath Elohim</em> -- 'No one knows the Father except the Son and anyone to whom the Son chooses to reveal him' (Matt 11:27). The covenant lawsuit of 4:1 names precisely what Christ provides: the truth, love, and knowledge of God that the land lacked.</p>",
        "2": "<p class='christ-theme'>The five covenant violations (cursing, lying, murder, stealing, adultery) that Hosea diagnoses in the land are the transgressions that Christ addresses through the Sermon on the Mount -- not by relaxing the standard but by deepening it to the level of the heart (Matt 5:21-48). The bloodshed following bloodshed describes the escalating violence that only the death of the Prince of Peace can ultimately break. 'He himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility' (Eph 2:14). The cycle of covenant violence is broken not by better law enforcement but by the one who absorbs the violence in himself.</p>",
        "3": "<p class='christ-theme'>The land mourning and creation's participation in covenant failure points to the creation-liberation that Christ's redemption secures. 'For the creation waits with eager longing for the revealing of the sons of God... the creation itself will be set free from its bondage to corruption' (Rom 8:19-21). The groaning of Hosea's land (beasts, birds, fish dying) is one voice in the larger creation-groan that Paul hears throughout the fallen order. Christ's resurrection is the first-fruits of creation's renewal: the new humanity revealed in the risen Christ is the pledge that the whole creation order will be liberated.</p>",
        "4": "<p class='christ-theme'>The state in which no one can accuse another because all are equally guilty is the condition Paul describes as the universal verdict of the law: 'None is righteous, no, not one' (Rom 3:10). The paralysis of mutual guilt -- everyone liable, no one qualified to judge -- is resolved by the one who had no sin yet bore the verdict: 'For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God' (2 Cor 5:21). Christ alone can stand outside the universal guilt to bear the verdict that no other can bear.</p>",
        "5": "<p class='christ-theme'>The stumbling of prophets and priests -- those who should be guides -- points to the human leadership's endemic failure to illuminate the way. Christ contrasts himself with all failed leadership: 'I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life' (John 8:12). The night in which Hosea's prophet stumbles is ended by the dawn that Christ brings (Luke 1:78-79: 'the sunrise shall visit us from on high to give light to those who sit in darkness and in the shadow of death, to guide our feet into the way of peace').</p>",
        "6": "<p class='christ-theme'>The destruction of Israel 'for lack of knowledge' and the rejection of the priestly vocation of teaching are met in Christ who is both the content and the teacher of the knowledge of God. 'In him are hidden all the treasures of wisdom and knowledge' (Col 2:3). He is the one who reveals the Father (Matt 11:27); the one whose words are spirit and life (John 6:63); the living Torah who fulfills rather than abolishes the law's intent to teach knowledge of God. The priestly vocation of teaching that Israel's priests rejected is taken up by Christ as the High Priest who mediates the knowledge of God to all who come to him.</p>",
        "7": "<p class='christ-theme'>Israel exchanged their glory (<em>kavod</em>) for shame -- the same exchange Paul describes in Rom 1:23: 'they exchanged the glory of the immortal God for images resembling mortal man and birds and animals and creeping things.' Christ reverses this exchange in the opposite direction: he who was the radiance of the Father's glory (Heb 1:3) 'exchanged' his glory for our shame: 'though he was rich, yet for your sake he became poor, so that you by his poverty might become rich' (2 Cor 8:9). The glory-for-shame exchange of idolatry is answered by the shame-for-glory exchange of the incarnation and cross.</p>",
        "8": "<p class='christ-theme'>The priests who feed on the sin of the people -- whose income depends on transgression continuing -- are the antitype of Christ the High Priest, who offers one sacrifice for sins once for all (Heb 10:12) precisely to make the ongoing economy of sin unnecessary. Where the corrupt Levitical priests needed sin to continue for their own benefit, Christ offers himself as the once-for-all offering that removes sin rather than managing it. 'He has no need, like those high priests, to offer sacrifices daily... he did this once for all when he offered up himself' (Heb 7:27). The priestly economy of Hosea's corrupt system is replaced by the once-for-all self-offering of the faithful High Priest.</p>",
        "9": "<p class='christ-theme'>The moral leveling -- 'like people, like priest' -- in which all share the same judgment is the precondition for the good news: if all are equally under judgment, all can equally receive the grace that is offered in Christ. 'For there is no distinction: for all have sinned and fall short of the glory of God, and are justified by his grace as a gift, through the redemption that is in Christ Jesus' (Rom 3:22-24). The leveling of Hosea's judgment opens the door to the leveling of the gospel: no one too good to need grace, no one too bad to receive it.</p>",
        "10": "<p class='christ-theme'>Eating but not being satisfied and pursuing fertility cult without flourishing is the futility of all substitutes for the true provision that only YHWH can give. Christ names himself as the one who satisfies what no substitute can: 'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst' (John 6:35). The satisfaction that Hosea's Israel was promised by the fertility cult -- and could not obtain -- is freely given to all who come to Christ. The hunger-without-satisfaction curse is lifted by the one who himself is the bread and water of life.</p>",
        "11": "<p class='christ-theme'>Prostitution, wine, and new wine 'take away the heart' -- the faculty of <em>lev</em> that enables covenant relationship. Christ promises to give a new heart (Ezek 36:26, the prophecy that his new covenant enacts): 'I will give you a new heart, and a new spirit I will put within you, and I will remove the heart of stone from your flesh and give you a heart of flesh.' The Spirit given at Pentecost is the antidote to the heart-taking intoxications of idolatry: the transformed heart (<em>lev chadash</em>) that can know YHWH is Christ's gift through the Spirit.</p>",
        "12": "<p class='christ-theme'>The consultation of wooden idols and the 'spirit of prostitution' that leads Israel astray is the spiritual bondage from which Christ liberates. 'You will know the truth, and the truth will set you free... if the Son sets you free, you will be free indeed' (John 8:32, 36). The spirit of prostitution that drives Israel away from YHWH is overcome by the Spirit of truth that Christ sends: 'When the Spirit of truth comes, he will guide you into all the truth' (John 16:13). The two spirits -- prostitution and truth -- are the alternatives that Hosea's Israel and the NT's hearers must choose between.</p>",
        "13": "<p class='christ-theme'>The mountaintop sacrifices and cult-prostitution at the high places are the shadow-religion that Christ's coming displaces. The woman at the well asked whether Jerusalem or Samaria was the right place to worship (John 4:20); Jesus answered that 'the hour is coming when neither on this mountain nor in Jerusalem will you worship the Father... true worshippers will worship the Father in spirit and truth' (John 4:21, 23). The geography of idolatry -- the high places, the shaded trees -- is replaced by the Spirit-and-truth worship that transcends location, enabled by the one who is himself the true Temple (John 2:21).</p>",
        "14": "<p class='christ-theme'>YHWH will not punish daughters alone when the men frequent the cult prostitutes -- the cause must be addressed, not only the symptom. Christ addresses the cause of all moral failure at the root: not merely prohibiting the act but transforming the desire. 'You have heard that it was said, You shall not commit adultery. But I say to you that everyone who looks at a woman with lustful intent has already committed adultery with her in his heart' (Matt 5:27-28). The Hosea diagnosis that the male heart (not only the female body) is the problem is the same diagnosis Christ applies -- and the same root that the new heart addresses.</p>",
        "15": "<p class='christ-theme'>The warning to Judah not to go to Gilgal or Beth-aven (the renamed Bethel) reflects the progressive corruption of cultic sites originally associated with covenant encounter. Christ's cleansing of the Temple (John 2:13-22; Mark 11:15-17) is the eschatological parallel: the site that should have been 'a house of prayer for all nations' has become 'a den of robbers.' The pattern -- sacred places corrupted by misuse -- runs through the OT and finds its resolution in Christ who becomes the true Temple, replacing the corruptible cultic geography with his own person.</p>",
        "16": "<p class='christ-theme'>Israel as a stubborn heifer that will not accept the yoke is the antitype of the one who willingly bears the yoke: 'Take my yoke upon you, and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls. For my yoke is easy, and my burden is light' (Matt 11:29-30). Christ offers the yoke of his kingship as the alternative to the stubbornness that refuses YHWH's guidance. The stubborn heifer that cannot be pastured is contrasted with the flock that recognizes the shepherd's voice (John 10:3-4) -- the new covenant community that responds to Christ's leading.</p>",
        "17": "<p class='christ-theme'>Ephraim 'joined to idols -- leave him alone' is the most chilling divine statement in Hosea: the withdrawal of striving. Paul's description of the pagan world in Rom 1:24-28 -- 'God gave them up' -- is the NT parallel: when a people persistently chooses idolatry over the truth, YHWH's response is to withdraw the restraint and allow the full consequences of the choice. Christ came specifically for those who were in this Ephraim condition: 'Those who are well have no need of a physician, but those who are sick... I came not to call the righteous, but sinners' (Matt 9:12-13). The 'leave him alone' of Hosea is not Christ's word but the word that makes Christ's intervention necessary.</p>",
        "18": "<p class='christ-theme'>The carousing and shameful love of the rulers -- the leadership's corruption that mirrors the people's idolatry -- is addressed by Christ's vision of servant leadership. 'Whoever would be great among you must be your servant, and whoever would be first among you must be slave of all' (Mark 10:43-44). The rulers of Hosea who love shame are the antitype of the servant-king who washes feet (John 13:5) and gives his life as a ransom for many (Mark 10:45). The honor-shame dynamic of Hosea's corrupt leadership is inverted in Christ: the one who could command serves, and the one who serves is exalted.</p>",
        "19": "<p class='christ-theme'>The wind sweeping away the idolaters in its wings and the shame of their sacrifices is the judgment that Christ's cross absorbs for those who turn from idols. 'You turned to God from idols to serve the living and true God, and to wait for his Son from heaven, whom he raised from the dead, Jesus who delivers us from the wrath to come' (1 Thess 1:9-10). The shame of the sacrifices offered to the Baals -- which cannot protect -- is contrasted with the sacrifice of Christ that does protect: 'Since we have now been justified by his blood, how much more shall we be saved from God's wrath through him' (Rom 5:9).</p>"
    },
    "5": {
        "1": "<p class='christ-theme'>The triple summons of priests, Israel, and royal house to hear YHWH's judgment is the OT prelude to the scene in which Christ stands before the same three structures -- priesthood (Caiaphas), people (the crowd), and royal authority (Pilate) -- and is condemned by all of them. The judgment that Hosea announces falls on those who were meant to administer it; at the trial of Jesus, the administrators of judgment become its perpetrators. But in condemning the one who was innocent, they enact the judgment of the covenant lawsuit on the one who bore it in their place (Acts 2:23: 'this Jesus, delivered up according to the definite plan and foreknowledge of God, you crucified and killed by the hands of lawless men').</p>",
        "2": "<p class='christ-theme'>The rebels sinking deep in their corruption while YHWH has been a discipline to all of them captures the human tendency to deepen transgression even as divine correction multiplies. Christ came into the full depth of this corruption: 'He had to be made like his brothers in every respect, so that he might become a merciful and faithful high priest... For because he himself has suffered when tempted, he is able to help those who are being tempted' (Heb 2:17-18). He entered the deepest pit of human failure not as one who stood above it but as one who was made like those in it -- so that he could pull them out from within.</p>",
        "3": "<p class='christ-theme'>YHWH's comprehensive knowledge of Ephraim ('I know Ephraim') is the backdrop for Christ's all-knowing intimacy with his people: 'I am the good shepherd. I know my own and my own know me' (John 10:14). The defilement of Israel that YHWH sees clearly -- nothing hidden from him -- is equally visible to Christ: 'he knew all people and needed no one to bear witness about man, for he himself knew what was in man' (John 2:24-25). But the knowing is not punitive judgment only; the shepherd knows the sheep in order to protect, guide, and lay down his life for them (John 10:11).</p>",
        "4": "<p class='christ-theme'>The deeds that prevent Israel from returning to God -- and the spirit of prostitution within them -- describe the bondage of the will that cannot repent by its own effort. Christ addresses this at the root: 'No one can come to me unless the Father who sent me draws him' (John 6:44). The new birth is required because the spirit of prostitution renders self-generated return impossible: 'That which is born of the flesh is flesh, and that which is born of the Spirit is spirit' (John 3:6). The Spirit of God must overcome the spirit of prostitution, replacing the inward drive away from God with the inward drive toward him -- the new heart of Ezek 36:26-27, which Christ gives.</p>",
        "5": "<p class='christ-theme'>Israel's arrogance testifying against him to his face is the self-condemnation of pride, contrasted with Christ's humility which stands in complete contrast: 'Though he was in the form of God, he did not count equality with God a thing to be grasped, but emptied himself, by taking the form of a servant' (Phil 2:6-7). The pride that made Ephraim stumble is the opposite of the kenosis that made Christ the source of salvation. The stumbling of arrogance is answered by the exaltation of humility: 'God opposes the proud but gives grace to the humble' (Jas 4:6) -- the principle Hosea illustrates is the principle Christ embodies.</p>",
        "6": "<p class='christ-theme'>Seeking YHWH with flocks and herds but not finding him because he has withdrawn is the failure of ritual without covenant. Christ is the one through whom YHWH is truly found: 'I am the way, and the truth, and the life. No one comes to the Father except through me' (John 14:6). The seeking with sacrificial animals (religious effort) that produces no access to God is answered by the Lamb who himself is the access: 'through him we both have access in one Spirit to the Father' (Eph 2:18). The sacrifices that Israel brought to find YHWH are replaced by the one sacrifice through which YHWH is permanently accessible.</p>",
        "7": "<p class='christ-theme'>The unfaithfulness to YHWH in bearing illegitimate children -- the syncretistic offspring of mixed worship -- is answered in Christ by the new birth that creates truly legitimate children of God: 'to all who did receive him, who believed in his name, he gave the right to become children of God, who were born, not of blood nor of the will of the flesh nor of the will of man, but of God' (John 1:12-13). The legitimacy problem of Hosea's Israel (children of zenutim) is resolved by adoption through Christ into the family of God -- a legitimacy that no syncretic compromise can take away.</p>",
        "8": "<p class='christ-theme'>The ram's horn and trumpet sounding the war alarm at Gibeah and Ramah are the OT's instruments of crisis. Christ reframes the same instruments in eschatological context: the trumpet that sounds at the end of the age (1 Cor 15:52; 1 Thess 4:16; Matt 24:31) announces not invasion but resurrection and gathering. The alarm-trumpet of Hosea's judgment becomes the gathering-trumpet of Christ's parousia. The crisis announced by Hosea's horn is absorbed in the cross; the trumpet of the last day announces the completion of what the cross secured.</p>",
        "9": "<p class='christ-theme'>Ephraim's desolation on the day of punishment is the covenant curse fully enacted. Christ absorbs this curse for those who are in him: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The certain (<em>nemannah</em>, trustworthy) declaration of YHWH about the judgment becomes, in Christ, the equally certain declaration of life: 'Truly, truly, I say to you, whoever hears my word and believes him who sent me has eternal life. He does not come into judgment, but has passed from death to life' (John 5:24).</p>",
        "10": "<p class='christ-theme'>The princes of Judah who move boundary stones -- defrauding the weak and expanding at others' expense -- are the antitype of Christ who voluntarily gave up what was his: 'though he was rich, yet for your sake he became poor, so that you by his poverty might become rich' (2 Cor 8:9). Where Judah's leaders seized others' territory, Christ surrendered his own. The wrath poured like water on those who defraud is met by the grace poured out on those who are in Christ: 'he poured out on us richly through Jesus Christ our Savior' (Titus 3:6).</p>",
        "11": "<p class='christ-theme'>Ephraim crushed and oppressed in justice, determined to pursue worthless idols, is the picture of the people Paul describes as enslaved to the elemental powers: 'formerly, when you did not know God, you were enslaved to those that by nature are not gods' (Gal 4:8). Christ's liberation from the crushing power of idolatry is the NT gospel: 'For freedom Christ has set us free; stand firm therefore, and do not submit again to a yoke of slavery' (Gal 5:1). The crushing of Ephraim that worthless idol-pursuit produces is reversed by the freedom that knowing the true God in Christ provides.</p>",
        "12": "<p class='christ-theme'>YHWH as moth to Ephraim and rot to Judah -- the slow invisible judgment -- contrasts with Christ who is the light that makes hidden things visible: 'For nothing is hidden that will not be made manifest, nor is anything secret that will not be known' (Luke 8:17). The slow decay of Hosea's moth-judgment is brought to its end in Christ's cross: the full accounting of sin is made visible there, where nothing is hidden. The rot that was destroying Israel from within is fully exposed and dealt with on the cross -- not ignored but exhausted in the one who bears it.</p>",
        "13": "<p class='christ-theme'>Ephraim seeking Assyria for healing -- the political solution to a covenant problem -- is the paradigm of all misdirected help-seeking. Christ names himself as the physician who addresses what no political or human power can cure: 'Those who are well have no need of a physician, but those who are sick. I came not to call the righteous, but sinners' (Matt 9:12-13). The great king of Assyria cannot heal the covenant wound; the Great Physician can. The seeking of foreign kings for help that only YHWH can give is the structural sin that the incarnation corrects by making the divine healer personally, humanly accessible.</p>",
        "14": "<p class='christ-allusion'>YHWH as lion tearing and carrying away -- divine judgment from which no one can rescue -- is the fearsome backdrop against which Christ's rescue mission is defined. He came specifically to rescue from the lion: 'Your adversary the devil prowls around like a roaring lion, seeking someone to devour' (1 Pet 5:8) -- and Christ is the stronger one who overcomes the strong man (Matt 12:29; Luke 11:21-22). The divine lion of judgment (Christ is also the Lion of Judah, Rev 5:5) is simultaneously the Lamb who was slain -- the one who absorbed the divine judgment so that the judgment-lion would not devour his people.</p>",
        "15": "<p class='christ-allusion'>YHWH's return to his place -- withdrawing from Israel until they acknowledge their guilt and seek his face -- foreshadows Christ's ascension and the inter-advent waiting. Christ returns to the Father's right hand (Acts 1:9-11; Heb 9:24) and 'those who eagerly await him' will see him return 'a second time... to save those who are eagerly waiting for him' (Heb 9:28). The distress that drives Israel to seek YHWH earnestly is the same dynamic the Spirit uses in the inter-advent period: the consciousness of need drives the earnest seeking that the returning Lord rewards. 'In their distress they will earnestly seek me' -- Christ's parousia answers this earnest seeking at the last.</p>"
    },
    "6": {
        "1": "<p class='christ-allusion'>The communal call to return -- 'Come, let us return to the LORD. He has torn us, but he will heal us' -- anticipates Jesus's invitation: 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28). The acknowledgment that YHWH both wounds and heals, tears and binds up, is fulfilled in Christ who bears the wound so that the healing comes to his people. On the cross, Christ is the one torn and wounded; in the resurrection, the healing that Hosea's Israel hopes for is enacted in history. 'He himself bore our sins in his body on the tree, that we might die to sin and live to righteousness. By his wounds you have been healed' (1 Pet 2:24).</p>",
        "2": "<p class='christ-allusion'>The third-day resurrection language -- 'After two days he will revive us; on the third day he will raise us up' -- is one of the OT's most significant anticipations of Christ's resurrection. Paul's summary of the gospel in 1 Cor 15:4 states that Christ 'was raised on the third day in accordance with the Scriptures' -- and Hosea 6:2 is among the Scriptures the NT tradition draws on (alongside Gen 22:4; Exod 19:11; Josh 1:11; 2 Kgs 20:5; Jonah 1:17). The 'we' of Hosea's corporate resurrection hope is realized in Christ's individual resurrection that guarantees the resurrection of all who are in him: 'Christ has been raised from the dead, the firstfruits of those who have fallen asleep' (1 Cor 15:20).</p>",
        "3": "<p class='christ-allusion'>The call to press on to know the LORD -- his appearing as certain as the dawn, his coming like the rain -- describes the knowledge of God that Christ makes accessible. 'No one knows the Father except the Son and anyone to whom the Son chooses to reveal him' (Matt 11:27). The dawn-certainty of YHWH's appearing finds its antitype in the resurrection dawn: 'early on the first day of the week, while it was still dark, Mary Magdalene came to the tomb' (John 20:1) -- the first light of Easter morning is the dawn of the new creation that Hosea's metaphor anticipates. The latter rain (<em>maqosh</em>) that refreshes the earth is a type of the Spirit poured out in Pentecost (Acts 2:17-18: 'I will pour out my Spirit on all flesh').</p>",
        "4": "<p class='christ-theme'>YHWH's exasperated question -- 'What shall I do with you, Ephraim? What shall I do with you, Judah?' -- is the expression of love frustrated by inconsistency. The morning cloud and early dew of Israel's love points to the contrast with Christ's love, which is anything but transient: 'Having loved his own who were in the world, he loved them to the end' (John 13:1). Where Israel's love evaporates before noon, Christ's endures through death. 'Who shall separate us from the love of Christ?' (Rom 8:35). The fleeting love that Hosea mourns finds its answer in the permanent, cross-proven love of Christ that neither morning cloud nor storm can dissipate.</p>",
        "5": "<p class='christ-theme'>YHWH having 'hewn them down by the prophets, slain them by the words of my mouth' is the divine word functioning as both judgment and revelation. Christ is the Word who both judges and saves: 'The word that I have spoken will judge him on the last day' (John 12:48) and 'the words that I have spoken to you are spirit and life' (John 6:63). The same word is both life-giving and slaying-of-the-old-self. Paul describes this as the living and active word: 'the word of God is living and active, sharper than any two-edged sword, piercing to the division of soul and of spirit' (Heb 4:12). Christ as the living Word is YHWH's prophet-ministry in person.</p>",
        "6": "<p class='christ-direct'>This is the most directly quoted verse in Hosea for Christ's own teaching. Jesus cites it twice: 'Go and learn what this means: I desire mercy, and not sacrifice. For I came not to call the righteous, but sinners' (Matt 9:13); 'And if you had known what this means, I desire mercy, and not sacrifice, you would not have condemned the guiltless' (Matt 12:7). In both citations, Jesus uses Hosea's principle to defend covenant love over ritual performance. The knowledge of God (<em>daath Elohim</em>) that Hosea sets above burnt offerings is identified with mercy (<em>chesed</em>) in practice -- the lived covenant love that the religious leaders had subordinated to cultic correctness. Christ himself is the embodiment of this principle: 'the Son of Man came not to be served but to serve, and to give his life as a ransom for many' (Mark 10:45) -- the ultimate act of <em>chesed</em> rather than sacrifice performed for personal benefit.</p>",
        "7": "<p class='christ-theme'>Israel's transgression 'like Adam' -- repeating the Edenic covenant violation -- is the typological frame for Christ as the second Adam who does not repeat the failure. 'As in Adam all die, so also in Christ shall all be made alive' (1 Cor 15:22). Paul's Adam-Christ typology (Rom 5:12-21) is the NT's extended commentary on Hosea 6:7: Adam transgressed the covenant; Christ obeyed where Adam disobeyed; the faithlessness of the one is answered by the faithfulness of the other. 'For as by the one man's disobedience the many were made sinners, so by the one man's obedience the many will be made righteous' (Rom 5:19).</p>",
        "8": "<p class='christ-theme'>Gilead stained with blood -- the city of evildoers whose iniquity is visible -- stands in contrast to Christ's blood which is the only blood that cleanses rather than stains. 'The blood of Jesus his Son cleanses us from all sin' (1 John 1:7). The blood that Gilead's violence produces is the blood that cries out for justice; the blood of Christ cries out for mercy: 'you have come to... Jesus, the mediator of a new covenant, and to the sprinkled blood that speaks a better word than the blood of Abel' (Heb 12:22, 24). The blood-stained city of Gilead is the antitype of the blood-cleansed people of the new covenant.</p>",
        "9": "<p class='christ-theme'>The bands of priests who murder on the road to Shechem -- spiritual leaders become predators -- are the antitype of Christ the Good Shepherd who lays down his life for the sheep rather than preying on them: 'The thief comes only to steal and kill and destroy. I came that they may have life and have it abundantly' (John 10:10). The road to Shechem was the road of covenant assembly; Christ makes the road of covenant encounter the road of abundant life rather than ambush. The murderous priesthood of Hosea is replaced by the High Priest who intercedes rather than preys: 'he always lives to make intercession for them' (Heb 7:25).</p>",
        "10": "<p class='christ-theme'>The 'horrible thing' seen in Israel -- Ephraim's prostitution, Israel's defilement -- is the condition that Christ comes to reverse through the cleansing of the new covenant. 'Christ loved the church and gave himself up for her, that he might sanctify her, having cleansed her by the washing of water with the word, so that he might present the church to himself in splendor, without spot or wrinkle or any such thing, that she might be holy and without blemish' (Eph 5:25-27). The defilement that Hosea identifies as Israel's condition is the condition Christ's sacrifice addresses: the bride who was defiled by prostitution is made clean by the bridegroom's self-giving.</p>",
        "11": "<p class='christ-theme'>Judah's appointed harvest -- ambiguous between judgment and restoration -- finds its resolution in Christ who is both the judge who reaps judgment (Rev 14:15-16) and the one who makes restoration possible. 'Do you not say, There are yet four months, then comes the harvest? Look, I tell you, lift up your eyes, and see that the fields are white for harvest' (John 4:35). The harvest that Hosea leaves ambiguous becomes, in Christ's ministry, the harvest of the nations coming into the kingdom -- the ingathering that the restored fortunes of God's people make possible. 'The harvest is plentiful, but the laborers are few; therefore pray earnestly to the Lord of the harvest to send out laborers into his harvest' (Matt 9:37-38).</p>"
    }
}

def main():
    existing = load_comm('mkt-christ', 'hosea')
    merge_comm(existing, HOSEA)
    save_comm('mkt-christ', 'hosea', existing)
    print('Hosea 1-6 mkt-christ written.')

if __name__ == '__main__':
    main()
